import { createSlice } from '@reduxjs/toolkit';


let initialState = {
	isLogin:false,
	isLoginFormOpen:false,
	isRegisterActive:false,
	userInfo:{
		id:'',
		username:''
	}
}

const accountSlice = createSlice({
	name:'account',
	initialState,
	reducers:{
		handleLogin:(state, action) => {
			console.log(action)
			state.isLogin = true
			state.userInfo.id = action.payload.id
			state.userInfo.username = action.payload.username
		},
		handleLogout:state => {
			state.isLogin = false
			state.userInfo.id = ''
			state.userInfo.username = ''
		},
		openLoginForm:(state) => {
			state.isLoginFormOpen = !state.isLoginFormOpen
		},
		switchLoginToRegister:(state) => {
			state.isRegisterActive = !state.isRegisterActive
		},
	}
})

export const {openLoginForm, closeLoginForm, switchLoginToRegister, handleLogin, handleLogout} = accountSlice.actions
export const accountSelector = state => state.account
export default accountSlice.reducer
